INSERT INTO game_category (id, slug, name, description, image, status, sort, created_at, updated_at, deleted_at, icon) VALUES ('cat_puzzle', 'puzzle', 'Puzzle', 'Puzzle games represent the perfect blend of entertainment and mental stimulation, offering players an opportunity to exercise their problem-solving skills while enjoying engaging gameplay. Our collection of puzzle games features a wide variety of challenges that test different aspects of cognitive function, from logical reasoning to pattern recognition.

