INSERT INTO game_category (id, slug, name, description, image, status, sort, created_at, updated_at, deleted_at, icon) VALUES ('cat_adventure', 'adventure', 'Adventure', 'Adventure games blend exploration, storytelling, and puzzle-solving to create rich, immersive journeys. Our adventure collection ranges from lighthearted platformers to deep, narrative-driven epics, giving players the freedom to explore mysterious worlds, uncover secrets, and make meaningful choices.

